protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // EF Core 9: HasIndex throws for Cosmos — manage indexing via Azure Portal/Bicep.
    // EF Core 9: Default discriminator renamed from "Discriminator" to "$type".
    // Preserve old name so existing documents remain queryable.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");
    // EF Core 9: id no longer includes discriminator (was "Blog|1", now "1").
    // Preserve old format so existing documents are still found by key.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
}

